import React, { useEffect, useState, useCallback } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid, ResponsiveContainer } from 'recharts';

const BASE = "http://localhost:5000/api/dashboard";

/* ========================================
   ADMIN DASHBOARD – matching screenshot
   ======================================== */
export function AdminDashboard({ onLogout }) {
  const [page, setPage] = useState('dashboard');
  const [data, setData] = useState(null);
  const [beneficiaries, setBeneficiaries] = useState([]);
  const [shops, setShops] = useState([]);
  const [stockList, setStockList] = useState([]);
  const [reports, setReports] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddShop, setShowAddShop] = useState(false);
  const [showUpdateStock, setShowUpdateStock] = useState(false);
  const [newShop, setNewShop] = useState({ name: '', location: '' });
  const [stockUpdate, setStockUpdate] = useState({ shop_id: '', rice: '', wheat: '' });

  const loadDashboard = useCallback(() => {
    fetch(`${BASE}/admin`).then(r => r.json()).then(setData).catch(() => {});
  }, []);

  useEffect(() => { loadDashboard(); }, [loadDashboard]);

  useEffect(() => {
    if (page === 'beneficiaries') fetch(`${BASE}/admin/beneficiaries`).then(r => r.json()).then(setBeneficiaries);
    if (page === 'shops') fetch(`${BASE}/admin/shops`).then(r => r.json()).then(setShops);
    if (page === 'stock') fetch(`${BASE}/admin/stock`).then(r => r.json()).then(setStockList);
    if (page === 'reports') fetch(`${BASE}/admin/reports`).then(r => r.json()).then(setReports);
  }, [page]);

  const handleAddShop = async () => {
    if (!newShop.name) return alert('Enter shop name');
    const res = await fetch(`${BASE}/admin/shops`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(newShop) });
    if (res.ok) { alert('Shop added!'); setShowAddShop(false); setNewShop({ name: '', location: '' }); loadDashboard(); if (page === 'shops') fetch(`${BASE}/admin/shops`).then(r => r.json()).then(setShops); }
  };

  const handleUpdateStock = async () => {
    if (!stockUpdate.shop_id) return alert('Enter shop ID');
    const res = await fetch(`${BASE}/admin/stock`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(stockUpdate) });
    if (res.ok) { alert('Stock updated!'); setShowUpdateStock(false); setStockUpdate({ shop_id: '', rice: '', wheat: '' }); loadDashboard(); if (page === 'stock') fetch(`${BASE}/admin/stock`).then(r => r.json()).then(setStockList); }
  };

  if (!data) return <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', fontSize: '16px', color: '#777' }}>Loading Dashboard...</div>;

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '🏠' },
    { id: 'beneficiaries', label: 'Beneficiaries', icon: '📋' },
    { id: 'shops', label: 'Ration Shops', icon: '🏪' },
    { id: 'stock', label: 'Stock', icon: '📦' },
    { id: 'reports', label: 'Reports', icon: '📊' },
  ];

  const filtered = (data.recentDistributions || []).filter(d =>
    !searchTerm ||
    (d.beneficiaryName || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
    (d.aadhaar || '').includes(searchTerm)
  );

  return (
    <div className="admin-layout">
      {/* ---- TOP HEADER BAR ---- */}
      <div className="top-header">
        <div className="top-header-left">
          <div className="home-icon">🏠</div>
          Smart Ration Distribution System
        </div>
        <div className="top-header-right">
          <div className="admin-info">
            <div className="admin-avatar">A</div>
            Admin
          </div>
          <button className="logout-top-btn" onClick={onLogout}>Logout</button>
          <span className="hamburger">☰</span>
        </div>
      </div>

      {/* ---- SIDEBAR ---- */}
      <div className="sidebar">
        <div className="sidebar-profile">
          <div className="avatar">👤</div>
          <p className="welcome-text">Welcome Admin</p>
          <span className="email-text">admin@example.com</span>
        </div>
        <div className="sidebar-nav">
          {navItems.map(item => (
            <div key={item.id} className={`sidebar-nav-item ${page === item.id ? 'active' : ''}`} onClick={() => setPage(item.id)}>
              <span className="nav-icon">{item.icon}</span>
              {item.label}
            </div>
          ))}
        </div>
        <div className="sidebar-logout">
          <button onClick={onLogout}>⏻ Logout</button>
        </div>
      </div>

      {/* ---- MAIN CONTENT ---- */}
      <div className="main-content">

        {/* ===== DASHBOARD PAGE ===== */}
        {page === 'dashboard' && (
          <div className="dashboard-content">
            <div className="welcome-section">
              <h2>Welcome to the Smart Ration Distribution System</h2>
              <p>Manage beneficiaries, ration shops, and stock efficiently and transparently.</p>
            </div>

            {/* Stat Cards */}
            <div className="stat-cards">
              <div className="stat-card green">
                <div className="stat-header"><div className="stat-icon">👥</div> Beneficiaries</div>
                <div className="stat-number">{data.beneficiaryCount}</div>
                <div className="stat-sub">Beneficiaries</div>
                <button className="stat-btn" onClick={() => setPage('beneficiaries')}>Add Beneficiary &nbsp;+</button>
              </div>
              <div className="stat-card orange">
                <div className="stat-header"><div className="stat-icon">🏪</div> Ration Shops</div>
                <div className="stat-number">{data.shopCount}</div>
                <div className="stat-sub">Ration Shops</div>
                <button className="stat-btn" onClick={() => setShowAddShop(true)}>Add Shop &nbsp;+</button>
              </div>
              <div className="stat-card blue">
                <div className="stat-header"><div className="stat-icon">📦</div> Stock</div>
                <div className="stat-number">{data.totalStock}</div>
                <div className="stat-sub">Total Allocated (kg)</div>
                <button className="stat-btn" onClick={() => setShowUpdateStock(true)}>Update Stock &nbsp;+</button>
              </div>
            </div>

            {/* Content Grid: Table + Summary */}
            <div className="content-grid">
              {/* Recent Distributions */}
              <div className="card">
                <div className="card-header">
                  <h3>Recent Distributions</h3>
                  <div className="search-box">
                    <span className="search-icon">🔍</span>
                    <input placeholder="Search..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                  </div>
                </div>
                <table className="data-table">
                  <thead>
                    <tr>
                      <th>Id</th>
                      <th>Beneficiary Name</th>
                      <th>Aadhaar No.</th>
                      <th>Shop</th>
                      <th>Date</th>
                      <th>Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filtered.length > 0 ? filtered.map((tx, i) => (
                      <tr key={i}>
                        <td>{tx.id}</td>
                        <td>{tx.beneficiaryName || '—'}</td>
                        <td>{tx.aadhaar || '—'}</td>
                        <td>{tx.shopName || '—'}</td>
                        <td>{new Date(tx.date).toLocaleDateString('en-IN')}</td>
                        <td><span className="status-badge delivered">Delivered</span></td>
                      </tr>
                    )) : (
                      <tr><td colSpan="6" style={{ textAlign: 'center', color: '#bbb', padding: '28px' }}>No distributions yet</td></tr>
                    )}
                  </tbody>
                </table>
                <div className="view-all-link">
                  <span onClick={() => setPage('reports')}>View All &gt;</span>
                </div>
              </div>

              {/* Right Summary */}
              <div className="summary-stack">
                <div className="summary-card">
                  <div className="s-icon stock-icon">📦</div>
                  <div className="s-text">
                    <h4>Total Stock</h4>
                    <p>{data.totalStock} <span style={{ fontSize: '14px', fontWeight: 400 }}>kg</span></p>
                  </div>
                </div>
                <div className="summary-card">
                  <div className="s-icon dist-icon">🚚</div>
                  <div className="s-text">
                    <h4>Distributed Stock</h4>
                    <p>{data.distributedStock} <span style={{ fontSize: '14px', fontWeight: 400 }}>kg</span></p>
                  </div>
                </div>
                <div className="summary-card">
                  <div className="s-icon alert-icon">⚠️</div>
                  <div className="s-text">
                    <h4>Low Stock Alerts</h4>
                    <p>{data.lowStockAlerts}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ===== BENEFICIARIES PAGE ===== */}
        {page === 'beneficiaries' && (
          <div className="sub-page">
            <h2>All Beneficiaries</h2>
            <div className="card">
              <table className="data-table">
                <thead>
                  <tr><th>ID</th><th>Name</th><th>Aadhaar</th><th>Ration Card</th><th>Category</th><th>Family</th><th>Mobile</th><th>City</th><th>Verified</th></tr>
                </thead>
                <tbody>
                  {beneficiaries.map((u, i) => (
                    <tr key={i}>
                      <td>{u.id}</td><td>{u.name}</td><td>{u.aadhaar}</td><td>{u.ration_card_number}</td>
                      <td>{u.ration_category}</td><td>{u.family_members}</td><td>{u.mobile_number}</td><td>{u.city}</td>
                      <td>{u.is_verified ? '✅' : '❌'}</td>
                    </tr>
                  ))}
                  {beneficiaries.length === 0 && <tr><td colSpan="9" style={{ textAlign: 'center', color: '#bbb', padding: '28px' }}>No beneficiaries found</td></tr>}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* ===== SHOPS PAGE ===== */}
        {page === 'shops' && (
          <div className="sub-page">
            <div className="page-top">
              <h2>Ration Shops</h2>
              <button className="action-btn" onClick={() => setShowAddShop(true)}>+ Add Shop</button>
            </div>
            <div className="card">
              <table className="data-table">
                <thead><tr><th>ID</th><th>Name</th><th>Location</th><th>Rice (kg)</th><th>Wheat (kg)</th></tr></thead>
                <tbody>
                  {shops.map((s, i) => (
                    <tr key={i}><td>{s.id}</td><td>{s.name}</td><td>{s.location}</td><td>{s.rice ?? 0}</td><td>{s.wheat ?? 0}</td></tr>
                  ))}
                  {shops.length === 0 && <tr><td colSpan="5" style={{ textAlign: 'center', color: '#bbb', padding: '28px' }}>No shops found</td></tr>}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* ===== STOCK PAGE ===== */}
        {page === 'stock' && (
          <div className="sub-page">
            <div className="page-top">
              <h2>Stock Management</h2>
              <button className="action-btn" onClick={() => setShowUpdateStock(true)}>+ Update Stock</button>
            </div>
            <div className="card" style={{ marginBottom: '20px' }}>
              <h3>Stock Overview</h3>
              <ResponsiveContainer width="100%" height={260}>
                <BarChart data={stockList.map(s => ({ name: s.shopName || `Shop ${s.shop_id}`, Rice: s.rice, Wheat: s.wheat }))}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="name" fontSize={12} />
                  <YAxis fontSize={12} />
                  <Tooltip />
                  <Bar dataKey="Rice" fill="#22c55e" radius={[4,4,0,0]} />
                  <Bar dataKey="Wheat" fill="#f97316" radius={[4,4,0,0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
            <div className="card">
              <table className="data-table">
                <thead><tr><th>Shop ID</th><th>Shop Name</th><th>Location</th><th>Rice (kg)</th><th>Wheat (kg)</th><th>Total</th></tr></thead>
                <tbody>
                  {stockList.map((s, i) => (
                    <tr key={i}><td>{s.shop_id}</td><td>{s.shopName || '—'}</td><td>{s.location || '—'}</td><td>{s.rice}</td><td>{s.wheat}</td><td>{s.rice + s.wheat}</td></tr>
                  ))}
                  {stockList.length === 0 && <tr><td colSpan="6" style={{ textAlign: 'center', color: '#bbb', padding: '28px' }}>No stock data</td></tr>}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* ===== REPORTS PAGE ===== */}
        {page === 'reports' && (
          <div className="sub-page">
            <h2>All Transaction Reports</h2>
            <div className="card">
              <table className="data-table">
                <thead><tr><th>ID</th><th>Beneficiary</th><th>Aadhaar</th><th>Shop</th><th>Rice</th><th>Wheat</th><th>Date</th></tr></thead>
                <tbody>
                  {reports.map((tx, i) => (
                    <tr key={i}><td>{tx.id}</td><td>{tx.beneficiaryName || '—'}</td><td>{tx.aadhaar || '—'}</td><td>{tx.shopName || '—'}</td><td>{tx.rice} kg</td><td>{tx.wheat} kg</td><td>{new Date(tx.date).toLocaleDateString('en-IN')}</td></tr>
                  ))}
                  {reports.length === 0 && <tr><td colSpan="7" style={{ textAlign: 'center', color: '#bbb', padding: '28px' }}>No transactions</td></tr>}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>

      {/* ---- ADD SHOP MODAL ---- */}
      {showAddShop && (
        <div className="modal-overlay" onClick={() => setShowAddShop(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h3>Add New Ration Shop</h3>
            <input className="modal-input" placeholder="Shop Name" value={newShop.name} onChange={e => setNewShop({ ...newShop, name: e.target.value })} />
            <input className="modal-input" placeholder="Location" value={newShop.location} onChange={e => setNewShop({ ...newShop, location: e.target.value })} />
            <div className="modal-actions">
              <button className="modal-btn cancel" onClick={() => setShowAddShop(false)}>Cancel</button>
              <button className="modal-btn primary" onClick={handleAddShop}>Add Shop</button>
            </div>
          </div>
        </div>
      )}

      {/* ---- UPDATE STOCK MODAL ---- */}
      {showUpdateStock && (
        <div className="modal-overlay" onClick={() => setShowUpdateStock(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h3>Update Stock</h3>
            <input className="modal-input" placeholder="Shop ID" type="number" value={stockUpdate.shop_id} onChange={e => setStockUpdate({ ...stockUpdate, shop_id: e.target.value })} />
            <input className="modal-input" placeholder="Rice (kg)" type="number" value={stockUpdate.rice} onChange={e => setStockUpdate({ ...stockUpdate, rice: e.target.value })} />
            <input className="modal-input" placeholder="Wheat (kg)" type="number" value={stockUpdate.wheat} onChange={e => setStockUpdate({ ...stockUpdate, wheat: e.target.value })} />
            <div className="modal-actions">
              <button className="modal-btn cancel" onClick={() => setShowUpdateStock(false)}>Cancel</button>
              <button className="modal-btn primary" onClick={handleUpdateStock}>Update Stock</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ========================================
   SHOPKEEPER DASHBOARD
   ======================================== */
export function ShopkeeperDashboard({ onLogout, shopId = 1 }) {
  const [data, setData] = useState(null);
  const [search, setSearch] = useState('');
  const [userResult, setUserResult] = useState(null);
  const [distribute, setDistribute] = useState({ rice: 0, wheat: 0 });

  const loadData = useCallback(() => {
    fetch(`${BASE}/shopkeeper/${shopId}`).then(r => r.json()).then(setData);
  }, [shopId]);

  useEffect(() => { loadData(); }, [loadData]);

  const handleSearch = async () => {
    const res = await fetch(`${BASE}/shopkeeper/search`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ aadhaar: search }) });
    if (res.ok) setUserResult(await res.json());
    else { alert('User not found'); setUserResult(null); }
  };

  const handleDistribute = async () => {
    const res = await fetch(`${BASE}/shopkeeper/distribute`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ user_id: userResult.id, shop_id: shopId, rice: distribute.rice, wheat: distribute.wheat }) });
    if (res.ok) { alert(await res.text()); loadData(); setUserResult(null); }
    else alert('Error distributing ration');
  };

  if (!data) return <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', color: '#777' }}>Loading...</div>;

  return (
    <div style={{ padding: '30px', maxWidth: '960px', margin: 'auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <h2 style={{ color: '#1a3a5c', fontWeight: 700 }}>Shopkeeper Dashboard</h2>
        <button className="action-btn danger" onClick={onLogout}>Logout</button>
      </div>
      <div className="stat-cards">
        <div className="stat-card green">
          <div className="stat-header"><div className="stat-icon">🌾</div> Rice Stock</div>
          <div className="stat-number">{data.currentStock.rice}</div>
          <div className="stat-sub">kg available</div>
        </div>
        <div className="stat-card orange">
          <div className="stat-header"><div className="stat-icon">🌾</div> Wheat Stock</div>
          <div className="stat-number">{data.currentStock.wheat}</div>
          <div className="stat-sub">kg available</div>
        </div>
        <div className="stat-card blue">
          <div className="stat-header"><div className="stat-icon">📋</div> Today's Txns</div>
          <div className="stat-number">{data.dailyTransactions.length}</div>
          <div className="stat-sub">transactions today</div>
        </div>
      </div>
      <div className="card" style={{ marginBottom: '20px' }}>
        <h3>Distribute Ration</h3>
        <div style={{ display: 'flex', gap: '10px', marginBottom: '14px' }}>
          <input className="modal-input" style={{ marginBottom: 0 }} placeholder="Search by Aadhaar" onChange={e => setSearch(e.target.value)} />
          <button className="action-btn" onClick={handleSearch}>Search</button>
        </div>
        {userResult && (
          <div style={{ padding: '14px', background: '#f9fafb', borderRadius: '10px', border: '1px solid #eee' }}>
            <p style={{ marginBottom: '4px' }}><strong>Name:</strong> {userResult.name}</p>
            <p style={{ marginBottom: '4px' }}><strong>Ration Card:</strong> {userResult.ration_card_number} ({userResult.ration_category})</p>
            <p style={{ marginBottom: '12px' }}><strong>Family:</strong> {userResult.family_members} members</p>
            <div style={{ display: 'flex', gap: '10px' }}>
              <input type="number" className="modal-input" style={{ marginBottom: 0 }} placeholder="Rice (kg)" onChange={e => setDistribute({ ...distribute, rice: e.target.value })} />
              <input type="number" className="modal-input" style={{ marginBottom: 0 }} placeholder="Wheat (kg)" onChange={e => setDistribute({ ...distribute, wheat: e.target.value })} />
              <button className="action-btn" onClick={handleDistribute}>Distribute</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

/* ========================================
   USER DASHBOARD
   ======================================== */
export function UserDashboard({ user, onLogout }) {
  const [data, setData] = useState(null);

  useEffect(() => {
    if (user?.id) fetch(`${BASE}/user/${user.id}`).then(r => r.json()).then(setData);
  }, [user]);

  if (!data) return <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', color: '#777' }}>Loading...</div>;

  const chartData = [
    { name: 'Rice', amount: data.entitlement.rice || 0 },
    { name: 'Wheat', amount: data.entitlement.wheat || 0 },
  ];

  return (
    <div style={{ padding: '30px', maxWidth: '960px', margin: 'auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <h2 style={{ color: '#1a3a5c', fontWeight: 700 }}>Hello, {data.user.name}</h2>
        <button className="action-btn danger" onClick={onLogout}>Logout</button>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.5fr', gap: '20px', marginBottom: '24px' }}>
        <div className="card">
          <h3>Personal Details</h3>
          <p style={{ margin: '6px 0', fontSize: '14px' }}><strong>Aadhaar:</strong> {data.user.aadhaar}</p>
          <p style={{ margin: '6px 0', fontSize: '14px' }}><strong>Ration Card:</strong> {data.user.ration_card_number}</p>
          <p style={{ margin: '6px 0', fontSize: '14px' }}><strong>Category:</strong> {data.user.category}</p>
          <p style={{ margin: '6px 0', fontSize: '14px' }}><strong>Family:</strong> {data.user.family_members} members</p>
        </div>
        <div className="card">
          <h3>Monthly Entitlement</h3>
          <ResponsiveContainer width="100%" height={140}>
            <BarChart layout="vertical" data={chartData} margin={{ left: 20 }}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis type="number" fontSize={12} />
              <YAxis type="category" dataKey="name" width={50} fontSize={12} />
              <Tooltip />
              <Bar dataKey="amount" fill="#2563eb" radius={[0, 4, 4, 0]} barSize={20} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
      <div className="card">
        <h3>Transaction History</h3>
        <table className="data-table">
          <thead><tr><th>Date</th><th>Shop</th><th>Rice (kg)</th><th>Wheat (kg)</th></tr></thead>
          <tbody>
            {data.transactionHistory.map((tx, i) => (
              <tr key={i}><td>{new Date(tx.date).toLocaleDateString('en-IN')}</td><td>{tx.shopName || tx.shop_id}</td><td>{tx.rice}</td><td>{tx.wheat}</td></tr>
            ))}
            {data.transactionHistory.length === 0 && <tr><td colSpan="4" style={{ textAlign: 'center', color: '#bbb', padding: '28px' }}>No transactions yet</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
}
